from collections import defaultdict
import sortedcontainers

class Solution(object):
    def processQueries(self, c, connections, queries):
        # Build adjacency list (1-indexed)
        adj = defaultdict(list)
        for u, v in connections:
            adj[u].append(v)
            adj[v].append(u)

        # Find connected components via BFS
        comp_id = [0] * (c + 1)  # comp_id[node] = component index
        visited = [False] * (c + 1)
        components = []  # components[i] = sorted set of nodes

        for start in range(1, c + 1):
            if not visited[start]:
                cid = len(components)
                comp = sortedcontainers.SortedList()
                stack = [start]
                while stack:
                    node = stack.pop()
                    if visited[node]:
                        continue
                    visited[node] = True
                    comp_id[node] = cid
                    comp.add(node)
                    for nb in adj[node]:
                        if not visited[nb]:
                            stack.append(nb)
                components.append(comp)

        result = []
        online = [True] * (c + 1)

        for qtype, x in queries:
            if qtype == 2:
                online[x] = False
                components[comp_id[x]].remove(x)
            else:  # qtype == 1
                if online[x]:
                    result.append(x)
                else:
                    comp = components[comp_id[x]]
                    result.append(comp[0] if comp else -1)

        return result
